--
-- Adds:
--   1. UPDATE stages · subtitle (re-set idempotent) + anchor_phrase + trap_warning · 15 rows
--   2. INSERT teaching_units · 45 rows · 3 lineages × 5 stages × 3 modes (listen/understand/reflect)
--      body jsonb populated with prototype data per mode · chapters column populated for listen
--   3. INSERT teacher_quotes · 15 rows · english_text + transliteration + source_ref
--
-- Idempotency:
--   - stages UPDATE is idempotent (overwrite to same values)
--   - teaching_units INSERT uses ON CONFLICT (id) DO NOTHING · deterministic id pattern
--   - teacher_quotes INSERT uses unique(lineage_id, stage_index, english_text) constraint added
--     at top of this migration · ON CONFLICT DO NOTHING
--
-- Note: V3 (`0003_content.sql`) created tables and seeded subtitles only ·
-- teaching_units rows did not pre-exist · this migration INSERTs them rather
-- than UPDATE per the original brief (flagged for CodeReview).


-- ─── 0. Add unique constraint to teacher_quotes for idempotent re-runs ────

alter table public.teacher_quotes
  add constraint uq_teacher_quotes_per_stage
  unique (lineage_id, stage_index, english_text);


-- ─── 1. UPDATE stages · subtitle + anchor_phrase + trap_warning · 15 rows ──

update public.stages
  set subtitle      = E'A whole-in-motion,\nnoticing the world',
      anchor_phrase = 'Buddho',
      trap_warning  = 'Austerity as identity — The practices become a badge. The forest becomes a costume.'
  where lineage_id = 'mun' and stage_index = 1;

update public.stages
  set subtitle      = E'Moments of stillness\nbegin to appear',
      anchor_phrase = 'Buddho',
      trap_warning  = 'Attachment to simplicity — Loving bareness is still loving something.'
  where lineage_id = 'mun' and stage_index = 2;

update public.stages
  set subtitle      = E'Attention softens,\nawareness deepens',
      anchor_phrase = 'Awareness',
      trap_warning  = 'Preferring stillness — The quiet mind becomes the new craving.'
  where lineage_id = 'mun' and stage_index = 3;

update public.stages
  set subtitle      = E'The mind rests, clear\nand unhurried',
      anchor_phrase = 'Citta',
      trap_warning  = 'Visions as attainment — Nimittā are signs, not destinations. Mun was clear.'
  where lineage_id = 'mun' and stage_index = 4;

update public.stages
  set subtitle      = E'No effort. Just being.',
      anchor_phrase = 'The unshaken',
      trap_warning  = 'Claiming the unshaken — Whoever claims it has not found it.'
  where lineage_id = 'mun' and stage_index = 5;

update public.stages
  set subtitle      = E'Sammā Arahaṃ —\narriving at the center',
      anchor_phrase = 'Sammā Arahaṃ',
      trap_warning  = 'Mantra as performance — Saying Sammā Arahaṃ is not doing it.'
  where lineage_id = 'sodh' and stage_index = 1;

update public.stages
  set subtitle      = E'Stopping itself\nis the fulfillment',
      anchor_phrase = 'Base 7',
      trap_warning  = 'Effort to stop — Trying to stop is still trying. Yud jung ja reo.'
  where lineage_id = 'sodh' and stage_index = 2;

update public.stages
  set subtitle      = E'The first sphere\nappears at Base 7',
      anchor_phrase = 'The first sphere',
      trap_warning  = 'Chasing the sphere — Reach, and it dims. Keep still, and it expands.'
  where lineage_id = 'sodh' and stage_index = 3;

update public.stages
  set subtitle      = E'Through eighteen bodies,\none inward movement',
      anchor_phrase = 'Center of center',
      trap_warning  = 'The ceiling feels like arrival — Deep samatha is luminous — and not yet vipassanā.'
  where lineage_id = 'sodh' and stage_index = 4;

update public.stages
  set subtitle      = E'The one path —\nwhat remains, remains',
      anchor_phrase = 'Dhammakāya',
      trap_warning  = 'None — we have passed — The warnings end. What remains, remains.'
  where lineage_id = 'sodh' and stage_index = 5;

update public.stages
  set subtitle      = E'Rain water —\nthe mind already pure',
      anchor_phrase = 'Feet on ground',
      trap_warning  = 'Reading the label — People debate the medicine. They don''t take it.'
  where lineage_id = 'chah' and stage_index = 1;

update public.stages
  set subtitle      = E'ไม่แน่ · not for sure.\nThe glass is already broken',
      anchor_phrase = 'ไม่แน่ · not for sure',
      trap_warning  = 'Rock on grass — Calm flattens the grass. Lift the rock: it returns.'
  where lineage_id = 'chah' and stage_index = 2;

update public.stages
  set subtitle      = E'The farmer watches\nthe buffalo · ผู้รู้',
      anchor_phrase = 'ผู้รู้ — the knower',
      trap_warning  = 'Drunk on Dhamma — The peace is pleasant. Don''t mistake the bar for home.'
  where lineage_id = 'chah' and stage_index = 3;

update public.stages
  set subtitle      = E'Both ends of the snake bite.\nWho is watching?',
      anchor_phrase = 'Who is watching?',
      trap_warning  = 'The red-hot iron ball — Every part is hot. There is no cool spot in the ball.'
  where lineage_id = 'chah' and stage_index = 4;

update public.stages
  set subtitle      = E'The tree does not know itself.\nIt is as it is.',
      anchor_phrase = 'The tree',
      trap_warning  = 'None — we have arrived past the point — No more warnings. Just the tree.'
  where lineage_id = 'chah' and stage_index = 5;


