insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('mun_1_listen_01', 'mun', 1, 'listen', 1, 'Leaving the House', 260, $json_v9_1$[{"t":"00:00","name":"The man who had everything","note":"A palace, a wife, a son — and one sleepless night"},{"t":"01:10","name":"Four things he stopped looking away from","note":"Birth, aging, sickness, death"},{"t":"02:30","name":"Dhamma arises in the forest","note":"Born, taught, awakened, passed — all under trees"},{"t":"03:30","name":"You are at the head of a path","note":"No need to be calm. No need to believe anything"}]$json_v9_1$::jsonb, $json_v9_2${"episode":"01","narrator":"Thai Forest tradition · LPM-019, LPM-036","duration":"04:20","duration_sec":260,"chapters":[{"t":"00:00","name":"The man who had everything","note":"A palace, a wife, a son — and one sleepless night"},{"t":"01:10","name":"Four things he stopped looking away from","note":"Birth, aging, sickness, death"},{"t":"02:30","name":"Dhamma arises in the forest","note":"Born, taught, awakened, passed — all under trees"},{"t":"03:30","name":"You are at the head of a path","note":"No need to be calm. No need to believe anything"}]}$json_v9_2$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('mun_1_understand_01', 'mun', 1, 'understand', 1, 'The body is not an obstacle to practice. The body is the practice.', $json_v9_3${"model_title":"The body is not an obstacle to practice. The body is the practice.","core_label":"This body","layers":[{"label":"Air · breath"},{"label":"Fire · warmth"},{"label":"Water · flow"},{"label":"Earth · bone"}],"concepts":[{"term":"นโม","romanized":"NAMO · THE FIRST BOW","note":"Na is water, the mother's element. Mo is earth, the father's element. To bow is to honor the substance you are made of."},{"term":"กรรมฐาน ๕","romanized":"KAMMAṬṬHĀNA 5 · FIVE OBJECTS","note":"Hair, body hair, nails, teeth, skin — the five given at ordination. Not a list. An invitation: look here. This is the starting point."},{"term":"ธาตุ ๔","romanized":"DHĀTU 4 · THE ELEMENTS","note":"Earth in bone, water in blood, fire in warmth, air in breath. The world moving through you, right now, as you walk."}],"comparison":[{"label":"Mind in the future / elsewhere","v":0.72},{"label":"Mind with the feet","v":0.28},{"label":"Mind knowing the elements","v":0.15}]}$json_v9_3$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('mun_1_reflect_01', 'mun', 1, 'reflect', 1, 'The Outer Path · reflection prompts', $json_v9_4${"questions":[{"prompt":"When you walk, how often does the body feel like it is doing the walking — rather than you directing it?","sub":"Not philosophically. In actual lived experience.","choices":[{"label":"Almost never — I am usually somewhere else entirely","v":1},{"label":"Briefly, once or twice per walk","v":2},{"label":"For stretches of minutes at a time","v":3},{"label":"Most of the walk unfolds this way","v":4}]},{"prompt":"How often do you notice the four elements moving in you — breath, warmth, flow, weight?","choices":[{"label":"I have never really noticed them","v":1},{"label":"Occasionally, if I remember to look","v":2},{"label":"Regularly, as part of walking","v":3},{"label":"They are a steady, quiet presence","v":4}]},{"prompt":"When your feet meet the ground, what quality do you actually experience?","sub":"Not \"the ground\" — hard, giving, rough, warm.","choices":[{"label":"I never notice — just \"walking\"","v":1},{"label":"Sometimes, if the surface changes","v":2},{"label":"Often, as a steady stream of sensation","v":3},{"label":"Continuously — the feet are the first thing I know","v":4}]},{"prompt":"Before teaching or performing, can you honestly acknowledge where you actually are?","sub":"LPM: one must train oneself before instructing others.","choices":[{"label":"I tend to perform where I am supposed to be","v":1},{"label":"I try, but the performing is strong","v":2},{"label":"Often — I can name what is true","v":3},{"label":"This honesty has become ordinary","v":4}]},{"prompt":"What have you left behind to walk today — even briefly?","sub":"Not literally. What did you set aside?","choices":[{"label":"Nothing — I brought it all with me","v":1},{"label":"One or two concerns, briefly","v":2},{"label":"The day's agenda, for the walk","v":3},{"label":"The whole apparatus of managing myself","v":4}]}],"bands":[{"label":"SETTING OUT","title":"The path is still new.","note":"You are at the head of the caṅkama. The mind has not yet agreed to walk with the body — and that is exactly what this stage is for.","suggestion":"Listen: \"Leaving the House\" · then a 15-minute walk with the body as sole instruction."},{"label":"ARRIVING","title":"The body is beginning to answer.","note":"The elements are no longer abstract. You can feel the earth in the feet and the air in the chest as a matter of fact, not belief.","suggestion":"Understand: \"The Body That Already Knows\" · then walk with posture instruction: right hand over left, gaze lowered."},{"label":"GROUNDED","title":"The outer path is walkable.","note":"You can arrive in the body within moments of starting. The ground is available. Stage 2 is within reach.","suggestion":"Reflect: \"What Are You Walking Toward?\" · then begin The Quiet Ground."}]}$json_v9_4$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('mun_2_listen_01', 'mun', 2, 'listen', 1, 'The Three Watches', 315, $json_v9_5$[{"t":"00:00","name":"One decision under a fig tree","note":"\"I will not get up until it is done\""},{"t":"01:20","name":"First watch — the chain of becoming","note":"Lifetimes seen as fire passing lamp to lamp"},{"t":"02:40","name":"Second watch — the larger pattern","note":"What you cultivate is what you become"},{"t":"04:00","name":"Third watch — the root","note":"Ignorance, thin as fog, seen through"}]$json_v9_5$::jsonb, $json_v9_6${"episode":"02","narrator":"Thai Forest tradition · LPM-020, LPM-033, LPM-061","duration":"05:15","duration_sec":315,"chapters":[{"t":"00:00","name":"One decision under a fig tree","note":"\"I will not get up until it is done\""},{"t":"01:20","name":"First watch — the chain of becoming","note":"Lifetimes seen as fire passing lamp to lamp"},{"t":"02:40","name":"Second watch — the larger pattern","note":"What you cultivate is what you become"},{"t":"04:00","name":"Third watch — the root","note":"Ignorance, thin as fog, seen through"}]}$json_v9_6$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('mun_2_understand_01', 'mun', 2, 'understand', 1, 'Three diseases, one medicine — complete, with no part optional.', $json_v9_7${"model_title":"Three diseases, one medicine — complete, with no part optional.","core_label":"Sīla · Samādhi · Paññā","layers":[{"label":"Paññā · wisdom"},{"label":"Samādhi · stillness"},{"label":"Sīla · intention"},{"label":"Rāga · Dosa · Moha"}],"concepts":[{"term":"ศีล","romanized":"SĪLA · INTENTION","note":"Cetanāhaṃ bhikkhave sīlaṃ vadāmi — intention is precept. Not rules imposed from outside, but the quality of a mind that chooses not to harm."},{"term":"สมาธิ","romanized":"SAMĀDHI · GATHERING","note":"The food of the mind. Not trance — the opposite: presence so complete that difficult sensations can be met without reacting."},{"term":"ปัญญา","romanized":"PAÑÑĀ · WISDOM","note":"What the mind does when it is clean, still, and honest. Not added — revealed, once sīla stabilizes the ground and samādhi steadies the instrument."}],"comparison":[{"label":"Reaching (rāga)","v":0.55},{"label":"Pushing away (dosa)","v":0.48},{"label":"Not-seeing (moha)","v":0.62}]}$json_v9_7$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('mun_2_reflect_01', 'mun', 2, 'reflect', 1, 'The Quiet Ground · reflection prompts', $json_v9_8${"questions":[{"prompt":"How often does sīla — the quality of not harming, not grasping — feel like intention rather than rule?","choices":[{"label":"It still feels like external rules I follow","v":1},{"label":"Sometimes it arises as intention","v":2},{"label":"Often — it feels like my own choice","v":3},{"label":"It is simply how the mind moves","v":4}]},{"prompt":"Can you stay with something longer than was comfortable, and find what is on the other side?","sub":"The second watch does not come without the first.","choices":[{"label":"I leave when it gets uncomfortable","v":1},{"label":"I sometimes stay, briefly","v":2},{"label":"I can stay through the first edge of difficulty","v":3},{"label":"I trust what is on the other side of staying","v":4}]},{"prompt":"Does the mind refine when the body's behavior refines?","sub":"External thin first, then internal becomes thin.","choices":[{"label":"I had not noticed the connection","v":1},{"label":"Occasionally I see it","v":2},{"label":"Often — composed outside, quieter inside","v":3},{"label":"They move as one thing","v":4}]},{"prompt":"Which of the three — sīla, samādhi, paññā — feels most available to you?","sub":"Not which you prefer. Which actually arises.","choices":[{"label":"None are reliably available yet","v":1},{"label":"One of them, sometimes","v":2},{"label":"Two of them, often","v":3},{"label":"All three, arising together","v":4}]},{"prompt":"When you walk for 20 minutes and then sit for 10, does the sitting feel different than usual?","choices":[{"label":"I have not tried the alternation","v":1},{"label":"Tried it — no difference","v":2},{"label":"The sitting deepens after the walk","v":3},{"label":"Walking and sitting have become one practice","v":4}]}],"bands":[{"label":"PLANTING","title":"Still learning to plant.","note":"The medicine is complete — you are still learning the parts. This is correct. Every session is a planting; the harvest comes later.","suggestion":"Listen: \"The Three Watches\" · then 20 walk / 10 sit alternation."},{"label":"TENDING","title":"The ground is receiving.","note":"Sīla and samādhi are becoming available as qualities, not projects. Keep the rhythm of walk-then-sit.","suggestion":"Understand: \"The Complete Medicine\" · longer sessions, same rhythm."},{"label":"HARVESTING","title":"The rice is cooked.","note":"When paññā is mature, the three are one thing. You are no longer building the tools — you are using them.","suggestion":"Reflect: \"Knowing in the Body\" · then move toward Stage 3."}]}$json_v9_8$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('mun_3_listen_01', 'mun', 3, 'listen', 1, 'The Horse Appeared', 340, $json_v9_9$[{"t":"00:00","name":"Looking at the wrong things","note":"A young monk's frustration — correct technique, still reaching"},{"t":"01:30","name":"Changing the direction","note":"Body analysis top to bottom, walking while looking"},{"t":"03:00","name":"The fallen tree, the horse","note":"The dream explained — wisdom-through-investigation"},{"t":"04:20","name":"The caṅkama is the sacred hall","note":"Not the route to practice — the practice itself"}]$json_v9_9$::jsonb, $json_v9_10${"episode":"03","narrator":"Thai Forest tradition · LPM-040 to 043","duration":"05:40","duration_sec":340,"chapters":[{"t":"00:00","name":"Looking at the wrong things","note":"A young monk's frustration — correct technique, still reaching"},{"t":"01:30","name":"Changing the direction","note":"Body analysis top to bottom, walking while looking"},{"t":"03:00","name":"The fallen tree, the horse","note":"The dream explained — wisdom-through-investigation"},{"t":"04:20","name":"The caṅkama is the sacred hall","note":"Not the route to practice — the practice itself"}]}$json_v9_10$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('mun_3_understand_01', 'mun', 3, 'understand', 1, 'Five layers. One moment. Arising together.', $json_v9_11${"model_title":"Five layers. One moment. Arising together.","core_label":"Rūpa · body-event","layers":[{"label":"Viññāṇa · knowing"},{"label":"Saṅkhāra · impulse"},{"label":"Saññā · recognition"},{"label":"Vedanā · feeling-tone"}],"concepts":[{"term":"สัญญา","romanized":"SAÑÑĀ · RECOGNITION","note":"The key troublemaker. Saññā mistakes the remembered image for reality — you hear \"tree\" and the label is already in the way."},{"term":"เวทนา","romanized":"VEDANĀ · FEELING-TONE","note":"The hinge. Before you know what you think about an experience, there is pleasant / unpleasant / neither. From this one split-second, the whole machinery activates."},{"term":"ทวนกระแส","romanized":"THON KRASUAE · TURN THE STREAM","note":"When nimitta arises, or the mind goes outward — turn it back. Not with force. With recognition. The stream always flows outward; practice is the returning."}],"comparison":[{"label":"Living in the label (saññā)","v":0.68},{"label":"Catching vedanā one beat earlier","v":0.42},{"label":"Meeting without becoming a project","v":0.35}]}$json_v9_11$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('mun_3_reflect_01', 'mun', 3, 'reflect', 1, 'The Inner Forest · reflection prompts', $json_v9_12${"questions":[{"prompt":"When something arises that you did not want — boredom, restlessness, a hard memory — can you meet it rather than push it away?","choices":[{"label":"I reliably push it away or distract","v":1},{"label":"I can meet it briefly before reacting","v":2},{"label":"I can stay with it through its peak","v":3},{"label":"Meeting has become more natural than pushing","v":4}]},{"prompt":"Do you catch vedanā — the pleasant/unpleasant quality — before you have narrated the experience?","sub":"One beat earlier than habitual reaction.","choices":[{"label":"I only notice after the story is built","v":1},{"label":"Occasionally I catch it mid-narration","v":2},{"label":"Often I notice the tone before the story","v":3},{"label":"Vedanā is visible as it arises","v":4}]},{"prompt":"When the mind wanders outward into thought or nimitta, can you turn the stream back — gently, not forcefully?","choices":[{"label":"The return is harsh, or I don't return","v":1},{"label":"I return but with effort and self-criticism","v":2},{"label":"The return is kind, most of the time","v":3},{"label":"Turning back has become the quality of the walk","v":4}]},{"prompt":"Can you feel the body changing in real time — breath deepening, muscles tiring, temperature shifting?","choices":[{"label":"I only notice in retrospect","v":1},{"label":"Sometimes during the walk","v":2},{"label":"The changes are a continuous stream","v":3},{"label":"Change itself is the meditation object","v":4}]},{"prompt":"When kilesā attack — sleepiness, wandering, the urge to stop — do you notice without obeying?","choices":[{"label":"I usually obey without noticing","v":1},{"label":"I notice, then negotiate with them","v":2},{"label":"I notice, name, and return to the walk","v":3},{"label":"They arise and pass without pulling me","v":4}]}],"bands":[{"label":"CLEARING","title":"The forest is still thick.","note":"You are beginning to see the interior weather as weather — not as you. This seeing is the entire work of this stage.","suggestion":"Listen: \"The Horse Appeared\" · then walk with body analysis top-to-bottom."},{"label":"WALKING THROUGH","title":"The paths are visible.","note":"Vedanā is becoming visible one beat earlier. The mind is learning to turn the stream back without harshness.","suggestion":"Understand: \"The Five Layers\" · walk noticing vedanā as primary object."},{"label":"AT HOME HERE","title":"The inner forest is familiar.","note":"Meeting what arises has become more natural than pushing. The kilesā announce themselves and are not obeyed.","suggestion":"Reflect: \"Meeting What Arises\" · then move toward Stage 4."}]}$json_v9_12$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('mun_4_listen_01', 'mun', 4, 'listen', 1, 'The Mind''s Own Face', 370, $json_v9_13$[{"t":"00:00","name":"A teaching few believe","note":"The mind is already pure. Not as aspiration — as fact"},{"t":"01:30","name":"Pabhassara citta · the luminous mind","note":"Defiled by visiting defilements, not permanent residents"},{"t":"03:15","name":"The sun and the clouds","note":"Practice is not cloud-removal. It is seeing the light exists independently"},{"t":"05:00","name":"Normalcy, finally recognized","note":"Not transcendence — the ordinary fact, seen"}]$json_v9_13$::jsonb, $json_v9_14${"episode":"04","narrator":"Thai Forest tradition · LPM-062, LPM-008, LPM-034","duration":"06:10","duration_sec":370,"chapters":[{"t":"00:00","name":"A teaching few believe","note":"The mind is already pure. Not as aspiration — as fact"},{"t":"01:30","name":"Pabhassara citta · the luminous mind","note":"Defiled by visiting defilements, not permanent residents"},{"t":"03:15","name":"The sun and the clouds","note":"Practice is not cloud-removal. It is seeing the light exists independently"},{"t":"05:00","name":"Normalcy, finally recognized","note":"Not transcendence — the ordinary fact, seen"}]}$json_v9_14$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('mun_4_understand_01', 'mun', 4, 'understand', 1, 'The mind at rest is like zero — empty of agenda, yet the source of all value.', $json_v9_15${"model_title":"The mind at rest is like zero — empty of agenda, yet the source of all value.","core_label":"0","layers":[{"label":"9 planes · the digits"},{"label":"Akiriyā · action without residue"},{"label":"Ṭhiticitta · mind that stands firm"},{"label":"Pabhassara · luminous"}],"concepts":[{"term":"จิตเดิม","romanized":"PABHASSARA CITTA · LUMINOUS MIND","note":"This mind, right now, has at its root a quality not touched by what moves through it. Practice does not create purity. It reveals what was never covered."},{"term":"ศูนย์","romanized":"SŪN · ZERO","note":"LPM's metaphor for the liberated mind. No conventional value alone, yet placed beside any digit makes it ten times its size. Moves through the world without being changed."},{"term":"ฐีติจิต","romanized":"ṬHITICITTA · THE STANDING MIND","note":"Not rigid. Not frozen. Simply — not swept. The mind that stands firm, the Dhamma that stands firm."}],"comparison":[{"label":"Identified with content","v":0.38},{"label":"Aware of awareness itself","v":0.58},{"label":"Resting as the ground","v":0.72}]}$json_v9_15$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('mun_4_reflect_01', 'mun', 4, 'reflect', 1, 'The Silent Temple · reflection prompts', $json_v9_16${"questions":[{"prompt":"Have you had a moment of awareness that felt prior to the contents of experience?","sub":"A knowing present before and after what you were aware of.","choices":[{"label":"I don't know what this refers to","v":1},{"label":"A glimpse, once or twice","v":2},{"label":"It has happened in meditation","v":3},{"label":"I can return to this recognition","v":4}]},{"prompt":"Do you experience your practice as revealing what was already present, rather than building something new?","choices":[{"label":"Practice still feels like construction","v":1},{"label":"Sometimes it feels like uncovering","v":2},{"label":"Revealing is the primary quality","v":3},{"label":"There is nothing to build — only to see","v":4}]},{"prompt":"Where in your life do you move \"as zero\" — acting without accumulating the action as identity?","choices":[{"label":"Everything I do becomes about me","v":1},{"label":"In small moments of care for others","v":2},{"label":"Often — action without residue","v":3},{"label":"This is becoming the normal quality","v":4}]},{"prompt":"What is the quality of your \"return\" when the mind has wandered — harsh or gentle?","choices":[{"label":"Harsh and exasperated","v":1},{"label":"Mixed — sometimes gentle, sometimes not","v":2},{"label":"Usually gentle and patient","v":3},{"label":"The return is indistinguishable from presence itself","v":4}]},{"prompt":"Is there something in you that notices when attention wanders — and that something did not wander?","sub":"Do not answer philosophically. Stay with it.","choices":[{"label":"I cannot locate this","v":1},{"label":"I sense it occasionally","v":2},{"label":"It is available when I look","v":3},{"label":"It is what I am, as the walk unfolds","v":4}]}],"bands":[{"label":"LISTENING","title":"The temple is still quiet to you.","note":"The teaching of an already-pure mind can sound like doctrine at first. Stay with the walk. The recognition arrives on its own schedule.","suggestion":"Listen: \"The Mind's Own Face\" · long sitting after a long walk."},{"label":"ENTERING","title":"You have heard the silence.","note":"The quality of awareness-behind-awareness is becoming visible. The zero-metaphor begins to mean something concrete.","suggestion":"Understand: \"Zero\" · sessions that rest rather than produce."},{"label":"AT REST","title":"The standing mind is steady.","note":"You return to the ground more easily than you leave it. Action without residue is no longer an abstraction.","suggestion":"Reflect: \"Returning\" · then move toward Stage 5."}]}$json_v9_16$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('mun_5_listen_01', 'mun', 5, 'listen', 1, 'The Narrow Passage', 405, $json_v9_17$[{"t":"00:00","name":"Mahā-sati surrounding body and mind","note":"Not only in formal sitting — in every breath"},{"t":"01:40","name":"When death comes through the narrow passage","note":"The moment the cultivated awareness either holds, or does not"},{"t":"03:30","name":"The fog no longer believed","note":"The Buddha's third watch — seeing through avijjā"},{"t":"05:15","name":"The lamp that has been lit","note":"Practice does not end. The form is how clarity expresses itself"}]$json_v9_17$::jsonb, $json_v9_18${"episode":"05","narrator":"Thai Forest tradition · LPM-029, LPM-033, LPM-020","duration":"06:45","duration_sec":405,"chapters":[{"t":"00:00","name":"Mahā-sati surrounding body and mind","note":"Not only in formal sitting — in every breath"},{"t":"01:40","name":"When death comes through the narrow passage","note":"The moment the cultivated awareness either holds, or does not"},{"t":"03:30","name":"The fog no longer believed","note":"The Buddha's third watch — seeing through avijjā"},{"t":"05:15","name":"The lamp that has been lit","note":"Practice does not end. The form is how clarity expresses itself"}]}$json_v9_18$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('mun_5_understand_01', 'mun', 5, 'understand', 1, 'How far the path goes — the four stages, precise, not vague.', $json_v9_19${"model_title":"How far the path goes — the four stages, precise, not vague.","core_label":"Vimutti","layers":[{"label":"Arahant · completed path"},{"label":"Anāgāmī · not returning"},{"label":"Sakadāgāmī · once-returner"},{"label":"Sotāpanna · stream-entered"}],"concepts":[{"term":"โสดาบัน","romanized":"SOTĀPANNA · STREAM-ENTERER","note":"Has seen the arising and passing of the khandhas directly. Three things permanently dissolve: self-belief, external-ritual seeking, fundamental doubt. Gone as a knot comes undone."},{"term":"อนาคามี","romanized":"ANĀGĀMĪ · NOT RETURNING","note":"Seclusion from sensuality is not effort-based — it is aj-jhāsaya, natural disposition. The way a bird is at home in air: not maintaining the flight, just flying."},{"term":"วิมุตติ","romanized":"VIMUTTI · LIBERATION","note":"All arahants attain both cetovimutti (liberation through heart) and paññāvimutti (liberation through wisdom). Not separate destinations. Where one is complete, the other is complete also."}],"comparison":[{"label":"Seeking an end","v":0.22},{"label":"Walking as the end","v":0.68},{"label":"No end, no means","v":0.85}]}$json_v9_19$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('mun_5_reflect_01', 'mun', 5, 'reflect', 1, 'Open Awareness · reflection prompts', $json_v9_20${"questions":[{"prompt":"What has been the \"narrow passage\" in your practice — the constraint that could only be moved through, not around?","choices":[{"label":"I still look for ways around","v":1},{"label":"I've moved through one or two","v":2},{"label":"Moving through has become the method","v":3},{"label":"There is nothing to move around — only through","v":4}]},{"prompt":"Which of the four awakening descriptions resonates as something you have tasted — not claimed?","sub":"Not as achievement. As a moment recognized.","choices":[{"label":"None — they sound like doctrine","v":1},{"label":"The stream-enterer — a glimpse","v":2},{"label":"The once-returner's altered relationship","v":3},{"label":"The anāgāmī's natural seclusion from sensuality","v":4}]},{"prompt":"How different is how you stand at the head of the path now, compared to your first walk?","choices":[{"label":"Not very different","v":1},{"label":"Noticeably different in some ways","v":2},{"label":"The standing itself is different","v":3},{"label":"There is no \"standing at the head\" — only this step","v":4}]},{"prompt":"Do you practice because there is more to attain — or because this step is what clarity does?","choices":[{"label":"Still to attain","v":1},{"label":"Mostly to attain, partly because this is how I am","v":2},{"label":"Mostly because this is how clarity expresses itself","v":3},{"label":"Entirely because the lamp is the lamp","v":4}]},{"prompt":"What do you actually know now, in the body and direct experience, that you did not know before?","sub":"Paccattaṃ — known inwardly. Not transmitted.","choices":[{"label":"I'm not sure I know anything new","v":1},{"label":"Something, but I could not name it","v":2},{"label":"Several things, each specific","v":3},{"label":"The knowing itself has changed","v":4}]}],"bands":[{"label":"APPROACHING","title":"The passage is visible.","note":"You can see the narrowing — the constraint you will have to move through. Seeing it clearly is already most of the work.","suggestion":"Listen: \"The Narrow Passage\" · a long walk alone, no agenda."},{"label":"PASSING THROUGH","title":"The narrow is now.","note":"The practice is no longer preparation. Each step is the passage. The form has become how clarity expresses itself in time.","suggestion":"Understand: \"How Far the Path Goes\" · sit with the four gates without claiming any."},{"label":"WALKING ON","title":"The path continues — without arriving.","note":"You have completed the five stages. You have not arrived anywhere. This is correct. The walk itself is what you were looking for.","suggestion":"Reflect: \"Walking Without Arriving\" · and keep walking."}]}$json_v9_20$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('sodh_1_listen_01', 'sodh', 1, 'listen', 1, 'The Night He Found It', 285, $json_v9_21$[{"t":"00:00","name":"A monk at a crossroads","note":"Twelve years of study. Every teacher: \"I have nothing more.\""},{"t":"01:10","name":"The vow under a full moon","note":"\"If I do not realize what the Buddha realized, I offer this life.\""},{"t":"02:30","name":"Stopping, and the sphere appears","note":"A crystal orb at the body's center. He kept still."},{"t":"03:40","name":"Two words that remain","note":"Sammā Arahaṃ — the anchor for the wandering mind"}]$json_v9_21$::jsonb, $json_v9_22${"episode":"01","narrator":"Vijjā Dhammakāya tradition · A01, A02, A03, B04, B06","duration":"04:45","duration_sec":285,"chapters":[{"t":"00:00","name":"A monk at a crossroads","note":"Twelve years of study. Every teacher: \"I have nothing more.\""},{"t":"01:10","name":"The vow under a full moon","note":"\"If I do not realize what the Buddha realized, I offer this life.\""},{"t":"02:30","name":"Stopping, and the sphere appears","note":"A crystal orb at the body's center. He kept still."},{"t":"03:40","name":"Two words that remain","note":"Sammā Arahaṃ — the anchor for the wandering mind"}]}$json_v9_22$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('sodh_1_understand_01', 'sodh', 1, 'understand', 1, 'The mantra is the rope. The center is the post. Stillness does the rest.', $json_v9_23${"model_title":"The mantra is the rope. The center is the post. Stillness does the rest.","core_label":"Sammā · Arahaṃ","layers":[{"label":"Paññā · wisdom arising"},{"label":"Samādhi · stillness holding"},{"label":"Sīla · clean foundation"},{"label":"The body · the ground"}],"concepts":[{"term":"สัมมา อะระหัง","romanized":"SAMMĀ ARAHAṂ · THE ANCHOR","note":"\"Sammā\" — in the right way, fully. \"Arahaṃ\" — the worthy one, the one who has arrived. Together, the Buddha's quality, called gently within yourself. Not belief. A handhold."},{"term":"ศูนย์กลางกาย","romanized":"SŪN-KLĀNG-KĀY · THE BODY CENTER","note":"Two finger-widths above the navel, inside the body. Not on skin — at the geometric center where all axes cross. One address, repeated for forty years."},{"term":"หยุด","romanized":"YUD · STOPPING","note":"Not stopping the body. Not stopping thoughts by force. The mind arriving at a single point and resting there — the one movement this whole path is built on."}],"comparison":[{"label":"Mind searching outward","v":0.74},{"label":"Mind held at the center","v":0.26},{"label":"Mantra moving with the breath","v":0.18}]}$json_v9_23$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('sodh_1_reflect_01', 'sodh', 1, 'reflect', 1, 'The Outer Path · reflection prompts', $json_v9_24${"questions":[{"prompt":"When you begin a walk or a sit, can you find the center of the body — the point two finger-widths above the navel, inside?","sub":"Not perfectly. Just: can you aim there?","choices":[{"label":"I cannot locate it — it is abstract","v":1},{"label":"I can find it, but lose it immediately","v":2},{"label":"I can aim there and stay for stretches","v":3},{"label":"The center has become a familiar place","v":4}]},{"prompt":"How does Sammā Arahaṃ sit on your breath?","choices":[{"label":"I forget it within seconds","v":1},{"label":"It comes and goes","v":2},{"label":"It rides the breath without effort","v":3},{"label":"It arises on its own, beneath thought","v":4}]},{"prompt":"When you walk, can you pair the mantra to your steps — Sammā on one foot, Arahaṃ on the next?","choices":[{"label":"I have not tried","v":1},{"label":"Tried it — it felt forced","v":2},{"label":"It has become a rhythm I return to","v":3},{"label":"Walking and mantra are one thing","v":4}]},{"prompt":"Are you searching for a state — or have you begun to simply stop?","sub":"Luang Pu Sodh: searching for twelve years. Finding it by not searching.","choices":[{"label":"Still searching — for calm, for insight","v":1},{"label":"Searching, with occasional stopping","v":2},{"label":"More stopping than searching","v":3},{"label":"The searching has quieted","v":4}]},{"prompt":"What happens when the mind wanders from the mantra?","choices":[{"label":"I criticize myself and force it back","v":1},{"label":"I notice and return, with some tightness","v":2},{"label":"I return without judgment","v":3},{"label":"The return is gentle; each return is the practice","v":4}]}],"bands":[{"label":"BEGINNING","title":"The path is new.","note":"You are at the head of the walk. The center is still an idea, not yet a place. This is exactly right. Hold the mantra loosely; let it teach you.","suggestion":"Listen: \"The Night He Found It\" · then a 15-minute walk with Sammā Arahaṃ at each step."},{"label":"FINDING THE ADDRESS","title":"The center is beginning to appear.","note":"You can aim at the body center. The mantra has a rhythm. The search has not ended, but it has softened.","suggestion":"Understand: \"The Anchor\" · walk with mantra, then sit for 5 minutes at the center."},{"label":"ARRIVED","title":"The outer path is walkable.","note":"The center is familiar. The mantra arises on its own. You are ready to stop — not as preparation, but as the practice itself.","suggestion":"Reflect: \"Stopping, Not Searching\" · then enter The Quiet Ground."}]}$json_v9_24$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('sodh_2_listen_01', 'sodh', 2, 'listen', 1, 'Stopping Is the Fulfillment', 330, $json_v9_25$[{"t":"00:00","name":"The paradox at the center","note":"Every tradition says \"do.\" He said: stop."},{"t":"01:30","name":"Stopping is not passive","note":"The most precise thing you will ever do"},{"t":"03:00","name":"The walking paradox","note":"If stopping is the fulfillment, what is walking for?"},{"t":"04:20","name":"The address: 0 — 7 — 2","note":"Zero, seventh base, two finger-widths above the navel"}]$json_v9_25$::jsonb, $json_v9_26${"episode":"02","narrator":"Vijjā Dhammakāya tradition · B01, B02, B11, B13, L05","duration":"05:30","duration_sec":330,"chapters":[{"t":"00:00","name":"The paradox at the center","note":"Every tradition says \"do.\" He said: stop."},{"t":"01:30","name":"Stopping is not passive","note":"The most precise thing you will ever do"},{"t":"03:00","name":"The walking paradox","note":"If stopping is the fulfillment, what is walking for?"},{"t":"04:20","name":"The address: 0 — 7 — 2","note":"Zero, seventh base, two finger-widths above the navel"}]}$json_v9_26$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('sodh_2_understand_01', 'sodh', 2, 'understand', 1, 'Seven bases, one destination. The mind moves through them, and rests at Base 7.', $json_v9_27${"model_title":"Seven bases, one destination. The mind moves through them, and rests at Base 7.","core_label":"ฐาน ๗","layers":[{"label":"07 · above the navel (rest here)"},{"label":"06 · navel · body crossroad"},{"label":"05 · throat · 04 · palate"},{"label":"01 – 03 · nose, eye, skull"}],"concepts":[{"term":"หยุดเป็นตัวสำเร็จ","romanized":"YUD PEN TUA SAMRET · STOPPING IS THE FULFILLMENT","note":"Not stopping to arrive somewhere. Stopping as the complete act. LPS's entire teaching compressed into six syllables — repeated to thousands of students across forty years."},{"term":"ฐานที่ ๗","romanized":"BASE 7 · THE SEVENTH BASE","note":"Two finger-widths above the navel, inside the body. Not the belly, not the heart — the geometric center where all axes intersect. The single destination. The address of stillness."},{"term":"หยุดจึงจะเร็ว","romanized":"YUD JUNG JA REO · STOPPING MAKES IT FAST","note":"The paradox LPS taught to anxious practitioners. Effort delays. Stopping reveals what was already there. \"Natthi santī paraṃ sukhaṃ\" — there is no happiness surpassing stillness."}],"comparison":[{"label":"Effort and pushing","v":0.62},{"label":"Trying to stop (still trying)","v":0.45},{"label":"Actual stopping","v":0.28}]}$json_v9_27$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('sodh_2_reflect_01', 'sodh', 2, 'reflect', 1, 'The Quiet Ground · reflection prompts', $json_v9_28${"questions":[{"prompt":"When your mind tries to meditate, does it still feel like doing?","choices":[{"label":"Meditation is always effortful doing","v":1},{"label":"Sometimes the doing falls away","v":2},{"label":"Doing often gives way to simply being still","v":3},{"label":"Meditation has stopped feeling like an activity","v":4}]},{"prompt":"Can you find the center of the body without searching for it?","sub":"Not concentrating hard. Simply aware that it is there.","choices":[{"label":"I still hunt for it","v":1},{"label":"Sometimes it is just present","v":2},{"label":"It is usually there when I look","v":3},{"label":"The center is always quietly known","v":4}]},{"prompt":"When walking, can you hold a soft awareness at Base 7 — not concentrating, just aware?","choices":[{"label":"Walking and Base 7 do not connect yet","v":1},{"label":"I can hold it briefly","v":2},{"label":"The awareness rides along with the steps","v":3},{"label":"Walking and center-awareness are one","v":4}]},{"prompt":"How do you meet impatience when the sphere does not appear?","sub":"LPS: the sphere is revealed, not created. You may sit for months before it comes.","choices":[{"label":"I get frustrated and push harder","v":1},{"label":"I push, then remember to soften","v":2},{"label":"I return to stopping without drama","v":3},{"label":"There is no rush — stopping is already enough","v":4}]},{"prompt":"Do walking and sitting feel like two things — or like one continuous practice?","choices":[{"label":"Two separate activities","v":1},{"label":"The sit feels different after a walk","v":2},{"label":"Walking prepares, sitting receives","v":3},{"label":"One practice with two forms","v":4}]}],"bands":[{"label":"LEARNING TO STOP","title":"The doing is still loud.","note":"You are learning the paradox — that trying harder delays the arrival. Let this stage be slow. The ground will receive.","suggestion":"Listen: \"Stopping Is the Fulfillment\" · then 20-minute walk, 10-minute sit at Base 7."},{"label":"RESTING AT THE CENTER","title":"The address is familiar.","note":"You find Base 7 without searching. The mantra arises on its own. Effort has begun to hollow into presence.","suggestion":"Understand: \"0 — 7 — 2\" · longer sits, same rhythm."},{"label":"STILL","title":"You are stopping, not striving.","note":"The paradox is no longer abstract. Each walk leads naturally into rest. The sphere may be close; do not reach for it.","suggestion":"Reflect: \"The Still Point\" · then enter The Inner Forest."}]}$json_v9_28$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('sodh_3_listen_01', 'sodh', 3, 'listen', 1, 'The First Light', 380, $json_v9_29$[{"t":"00:00","name":"The body that dreams","note":"Everyone has experienced it — every night, without knowing"},{"t":"01:30","name":"Awake dreaming","note":"Meeting the refined body consciously, not swept along"},{"t":"03:00","name":"What appears when you stop","note":"A sphere, the size of an egg yolk. Crystal clear."},{"t":"04:40","name":"The one-and-only path","note":"Ekāyana — all Buddhas entered through this single sphere"}]$json_v9_29$::jsonb, $json_v9_30${"episode":"03","narrator":"Vijjā Dhammakāya tradition · F01, F02, F03, L05, C01, C02","duration":"06:20","duration_sec":380,"chapters":[{"t":"00:00","name":"The body that dreams","note":"Everyone has experienced it — every night, without knowing"},{"t":"01:30","name":"Awake dreaming","note":"Meeting the refined body consciously, not swept along"},{"t":"03:00","name":"What appears when you stop","note":"A sphere, the size of an egg yolk. Crystal clear."},{"t":"04:40","name":"The one-and-only path","note":"Ekāyana — all Buddhas entered through this single sphere"}]}$json_v9_30$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('sodh_3_understand_01', 'sodh', 3, 'understand', 1, 'Not created by meditation. Revealed by stillness. Each sphere is a doorway to the next.', $json_v9_31${"model_title":"Not created by meditation. Revealed by stillness. Each sphere is a doorway to the next.","core_label":"ดวง · the sphere","layers":[{"label":"Center of the center · the next body"},{"label":"A pinprick of light · ทางสายกลาง"},{"label":"Expanding · brighter than a mirror"},{"label":"First appearing · the size of an egg yolk"}],"concepts":[{"term":"ดวงปฐมมรรค","romanized":"DUANG PATHAMA-MAGGA · THE FIRST-PATH SPHERE","note":"The first sphere to appear at Base 7 when the mind stops. Crystal clear, bright as a mirror. LPS named it \"ดวงธัมมานุปัสสนาสติปัฏฐาน\" — the sphere of dhamma-contemplation, arrived at directly, not deduced."},{"term":"เอกายนมรรค","romanized":"EKĀYANA-MAGGA · THE ONE-AND-ONLY PATH","note":"Every Buddha, every arahant — according to LPS — entered Nibbāna through this single sphere. No alternatives, no forks. Only the speed of arrival varies, depending on what each practitioner has cultivated."},{"term":"กายมนุษย์ละเอียด","romanized":"KĀY MANUT LA-IAT · THE REFINED HUMAN BODY","note":"The body that leaves when you dream. You already have one. You have already experienced it. The question is whether you can meet it consciously, awake — one step inward from the body that walks."}],"comparison":[{"label":"Looking for the sphere","v":0.55},{"label":"Receiving what appears","v":0.65},{"label":"Center of center — going inward","v":0.4}]}$json_v9_31$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('sodh_3_reflect_01', 'sodh', 3, 'reflect', 1, 'The Inner Forest · reflection prompts', $json_v9_32${"questions":[{"prompt":"Have you experienced a sense of lightness or inner presence during deep stillness — as if something lighter than the body was there?","sub":"Not visualized. Not imagined. Noticed.","choices":[{"label":"I have not noticed anything like this","v":1},{"label":"A brief sense, once or twice","v":2},{"label":"It has arisen in several sittings","v":3},{"label":"I can find it when the mind is still","v":4}]},{"prompt":"When something appears in meditation — a light, a sensation, an image — how do you meet it?","sub":"LPS: do not reach. Keep still. It expands when unmolested.","choices":[{"label":"I chase it and it vanishes","v":1},{"label":"I reach, then remember to stop","v":2},{"label":"I keep still and watch","v":3},{"label":"Reaching and pushing are no longer habits","v":4}]},{"prompt":"Can you tell the difference between imagining a sphere of light and actually seeing one?","sub":"Honest answer. This is the whole point of the tradition.","choices":[{"label":"I cannot tell the difference","v":1},{"label":"I sense there is a difference but am unsure","v":2},{"label":"I can tell — imagination has effort; seeing does not","v":3},{"label":"Seeing has become unmistakable","v":4}]},{"prompt":"Do you dream more vividly since beginning this practice?","choices":[{"label":"No change","v":1},{"label":"Slightly more vivid","v":2},{"label":"Noticeably more lucid and directed","v":3},{"label":"I can meet the dream-body consciously at times","v":4}]},{"prompt":"When you rest at Base 7, does something feel like it is already there — waiting?","choices":[{"label":"The center feels empty","v":1},{"label":"Sometimes there is a quiet sense of something","v":2},{"label":"Something is there; I do not know what","v":3},{"label":"The presence is unmistakable","v":4}]}],"bands":[{"label":"LOOKING","title":"The first light has not yet appeared.","note":"This is expected. The sphere arrives on no schedule. Your task is simply to stop — and to distinguish the reaching from the receiving.","suggestion":"Listen: \"The First Light\" · long walk, long sit, no agenda."},{"label":"THE FIRST GLIMPSE","title":"Something has appeared.","note":"A light, a presence, a sense of something waiting at the center. Do not claim it. Do not reach for it. Keep still — it expands.","suggestion":"Understand: \"Spheres Within Spheres\" · sit for longer than feels comfortable."},{"label":"SEEING","title":"The sphere is familiar.","note":"What appears is no longer imagined. You are ready for the center of the center — the movement that leads inward, through the nested bodies.","suggestion":"Reflect: \"What You Have Seen\" · then enter The Silent Temple."}]}$json_v9_32$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('sodh_4_listen_01', 'sodh', 4, 'listen', 1, 'The Eighteen', 420, $json_v9_33$[{"t":"00:00","name":"The map inside the body","note":"Not metaphors. Eighteen distinct experiential bodies."},{"t":"01:40","name":"The eight bodies of the world","note":"Human · heavenly · form-brahma · formless — samatha's ceiling"},{"t":"03:30","name":"Crossing the boundary","note":"Body nine — the Dhamma-body — vipassanā begins"},{"t":"05:00","name":"Six spheres, entered in sequence","note":"Virtue · stillness · wisdom · freedom · the knowing of freedom"},{"t":"06:20","name":"Center of the center","note":"The one movement traversing the whole path"}]$json_v9_33$::jsonb, $json_v9_34${"episode":"04","narrator":"Vijjā Dhammakāya tradition · E01-E05, L01, L02, L04, F07","duration":"07:00","duration_sec":420,"chapters":[{"t":"00:00","name":"The map inside the body","note":"Not metaphors. Eighteen distinct experiential bodies."},{"t":"01:40","name":"The eight bodies of the world","note":"Human · heavenly · form-brahma · formless — samatha's ceiling"},{"t":"03:30","name":"Crossing the boundary","note":"Body nine — the Dhamma-body — vipassanā begins"},{"t":"05:00","name":"Six spheres, entered in sequence","note":"Virtue · stillness · wisdom · freedom · the knowing of freedom"},{"t":"06:20","name":"Center of the center","note":"The one movement traversing the whole path"}]}$json_v9_34$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('sodh_4_understand_01', 'sodh', 4, 'understand', 1, 'Eighteen bodies. The boundary between world-becoming and liberation runs through the Dhamma-body.', $json_v9_35${"model_title":"Eighteen bodies. The boundary between world-becoming and liberation runs through the Dhamma-body.","core_label":"ธรรมกาย","layers":[{"label":"18 · Arahant body (refined)"},{"label":"9–17 · lokuttara — beyond the world"},{"label":"── boundary: the Dhamma-body ──"},{"label":"1–8 · lokīya — samatha, still in the world"}],"concepts":[{"term":"๑๘ กาย","romanized":"18 KĀY · EIGHTEEN BODIES","note":"Nine pairs, coarse and refined. Human · heavenly · form-brahma · formless-brahma · Dhamma-body · stream-entry · once-returner · non-returner · arahant. Each nested in the center of the previous one."},{"term":"กลางของกลาง","romanized":"KLĀNG KHONG KLĀNG · CENTER OF THE CENTER","note":"The one movement. Each sphere and each body is accessed by going to the center of what appeared before. Not technique shifting — one motion, repeated, inward."},{"term":"ธรรมกาย","romanized":"DHAMMAKĀYA · THE DHAMMA-BODY","note":"Body #9. Shaped like a Buddha image, lotus-bud crown, crystal-clear as a mirror. The boundary between samatha and vipassanā. \"When you reach it, you have left the world of becoming.\""}],"comparison":[{"label":"Deep samatha (bodies 3–8)","v":0.45},{"label":"Traversing the six spheres","v":0.55},{"label":"Dhamma-body recognized","v":0.3}]}$json_v9_35$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('sodh_4_reflect_01', 'sodh', 4, 'reflect', 1, 'The Silent Temple · reflection prompts', $json_v9_36${"questions":[{"prompt":"When you enter deep stillness, does it feel like a depth you could go further into — or like the bottom of something?","sub":"LPS: the ceiling of samatha feels like arrival. It isn't.","choices":[{"label":"I haven't reached deep stillness yet","v":1},{"label":"It feels like the bottom — I assume that's it","v":2},{"label":"I sense there is further, though I don't know how","v":3},{"label":"I have moved through what felt like a ceiling","v":4}]},{"prompt":"Can you hold the center-of-the-center movement — going inward through what appears, rather than stopping at it?","choices":[{"label":"I don't know what this movement is","v":1},{"label":"I grasp the idea but can't do it","v":2},{"label":"The movement is available when the mind is still","v":3},{"label":"It has become the natural direction of practice","v":4}]},{"prompt":"How do you relate to the 18-body map — as doctrine, or as territory?","sub":"No wrong answer. LPS said the map is only useful if you are walking.","choices":[{"label":"It sounds like mythology","v":1},{"label":"I hold it as a possibility","v":2},{"label":"It describes something I have begun to taste","v":3},{"label":"The map and my experience correspond","v":4}]},{"prompt":"Between sittings — do ethics, stillness, and wisdom feel like three separate qualities, or like one?","sub":"The six spheres teach: they must each be entered. One cannot be skipped.","choices":[{"label":"Three separate projects","v":1},{"label":"Connected, but distinct","v":2},{"label":"Increasingly one quality","v":3},{"label":"One thing with three names","v":4}]},{"prompt":"If the Dhamma-body is real, how would you know you had reached it?","sub":"A question, not a test. Stay with what you do not know.","choices":[{"label":"I have no basis for knowing","v":1},{"label":"By the visual description in the teaching","v":2},{"label":"By the quality of the knowing — not just deeper calm","v":3},{"label":"I would know because something else would know","v":4}]}],"bands":[{"label":"AT THE CEILING","title":"Samatha has a ceiling.","note":"Deep calm is real, and it is not yet liberation. This stage is the honest confrontation with that gap — the first eight bodies, luminous but impermanent.","suggestion":"Listen: \"The Eighteen\" · long sit after a long walk. Do not claim anything."},{"label":"CROSSING","title":"The boundary is visible.","note":"The center-of-the-center movement is available. Something about the quality of knowing is beginning to shift — not deeper, different.","suggestion":"Understand: \"Samatha and Vipassanā\" · rest at Base 7 without pursuing."},{"label":"THE TEMPLE","title":"You have entered.","note":"The Dhamma-body is no longer only a name. What you have tasted cannot be unlearned. The remaining bodies are a matter of time, not of method.","suggestion":"Reflect: \"The Dhamma-Body\" · then enter Open Awareness."}]}$json_v9_36$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('sodh_5_listen_01', 'sodh', 5, 'listen', 1, 'What Remains', 440, $json_v9_37$[{"t":"00:00","name":"The one path","note":"Ekāyana — every Buddha, every arahant, one road"},{"t":"01:40","name":"Twenty-two years, eight months","note":"LPS framed his teaching as warfare against aging and death"},{"t":"03:30","name":"No need to die to reach it","note":"Nibbāna while walking — when the perfections are complete"},{"t":"05:10","name":"The Dhamma-body is the Tathāgata","note":"Seeing is seeing. Not inference. Not inheritance."},{"t":"06:30","name":"What remains","note":"The lamp is the lamp. The walk is the walk."}]$json_v9_37$::jsonb, $json_v9_38${"episode":"05","narrator":"Vijjā Dhammakāya tradition · G01, G02, G03, H04, H05, L05","duration":"07:20","duration_sec":440,"chapters":[{"t":"00:00","name":"The one path","note":"Ekāyana — every Buddha, every arahant, one road"},{"t":"01:40","name":"Twenty-two years, eight months","note":"LPS framed his teaching as warfare against aging and death"},{"t":"03:30","name":"No need to die to reach it","note":"Nibbāna while walking — when the perfections are complete"},{"t":"05:10","name":"The Dhamma-body is the Tathāgata","note":"Seeing is seeing. Not inference. Not inheritance."},{"t":"06:30","name":"What remains","note":"The lamp is the lamp. The walk is the walk."}]}$json_v9_38$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('sodh_5_understand_01', 'sodh', 5, 'understand', 1, 'One path. One method. The speed of arrival is the only variable.', $json_v9_39${"model_title":"One path. One method. The speed of arrival is the only variable.","core_label":"เอกายนมรรค","layers":[{"label":"Arahant body · the task is complete"},{"label":"Non-returner · once-returner"},{"label":"Stream-entry · Dhamma-body"},{"label":"The single sphere at the center"}],"concepts":[{"term":"เอกายนมรรค","romanized":"EKĀYANA-MAGGA · THE ONE PATH","note":"\"The path with no second.\" LPS taught: every Buddha and every arahant entered Nibbāna through this single sphere. Not one path among several — the sole path. Speed varies. The road does not."},{"term":"อายตนนิพพาน","romanized":"ĀYATANA-NIBBĀNA · THE NIBBĀNA-SPHERE","note":"LPS spoke of Nibbāna not as cessation alone, but as a populated realm — countless Buddhas who have shed their bodies across countless world-systems. A teaching to be held with honesty: his framing, not universally accepted, reported as observed."},{"term":"ธรรมกายคือตถาคต","romanized":"DHAMMAKĀYA = TATHĀGATA","note":"LPS cited the Pāli canon: \"Tathāgatassa etaṃ adhivacanaṃ — Dhammakāyo.\" The Dhamma-body is a name for the Tathāgata. To see the Dhamma-body is, in his framing, literally to see the Buddha — within, not without."}],"comparison":[{"label":"Practice as preparation","v":0.22},{"label":"Practice as how clarity walks","v":0.65},{"label":"No practice, only the walking","v":0.82}]}$json_v9_39$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('sodh_5_reflect_01', 'sodh', 5, 'reflect', 1, 'Open Awareness · reflection prompts', $json_v9_40${"questions":[{"prompt":"Do you practice because there is still something to attain — or because this is what clarity does?","choices":[{"label":"Entirely to attain something","v":1},{"label":"Mostly to attain, partly as expression","v":2},{"label":"Mostly as expression, some seeking remains","v":3},{"label":"The lamp is the lamp","v":4}]},{"prompt":"LPS taught that Nibbāna does not require dying. How do you hold this?","sub":"Not a belief test. A question about what you have tasted.","choices":[{"label":"I treat it as a teaching I hold at arm's length","v":1},{"label":"I can feel there might be something to it","v":2},{"label":"I have tasted moments that point in this direction","v":3},{"label":"The distinction between seeking and having has thinned","v":4}]},{"prompt":"When you think of your own aging and death, how does the practice meet it?","sub":"LPS framed his forty-year teaching as warfare against these three.","choices":[{"label":"The practice does not reach this","v":1},{"label":"There is some softening of fear","v":2},{"label":"The body's impermanence is held with clarity","v":3},{"label":"What remains cannot age. What ages is not what remains.","v":4}]},{"prompt":"Of the controversial claims in this lineage — the Dhamma-body, the populated Nibbāna, the cosmic Māra — which do you hold as real?","sub":"Honesty, not performance. It is fine to hold none.","choices":[{"label":"None — I practice, I do not hold the doctrine","v":1},{"label":"The Dhamma-body, tentatively, as an experience to test","v":2},{"label":"Several — I have had corresponding experiences","v":3},{"label":"The framings feel like descriptions of what is","v":4}]},{"prompt":"What actually remains — in the body, in the knowing — from this path?","sub":"Paccattaṃ veditabbo viññūhi · known inwardly, by the wise, for themselves.","choices":[{"label":"I am not sure anything has remained","v":1},{"label":"Something, that I cannot name","v":2},{"label":"Several things, specific and enduring","v":3},{"label":"The remaining has become the ordinary fact","v":4}]}],"bands":[{"label":"APPROACHING","title":"The one path is visible.","note":"You can see the road without forks. This seeing is most of the arrival. Keep walking — the speed is not the point.","suggestion":"Listen: \"What Remains\" · a long walk alone, no destination."},{"label":"WALKING","title":"The lamp is lit.","note":"Practice has stopped being preparation. Each step is the passage. Aging, illness, and fear are not absent — they are met.","suggestion":"Understand: \"The One Path\" · sit with the six spheres without naming."},{"label":"ARRIVED WITHOUT ARRIVING","title":"What remains, remains.","note":"You have completed the five stages of this lineage. You have not arrived anywhere. That is what arrival looks like on this path.","suggestion":"Reflect: \"Paccattaṃ\" · and keep walking."}]}$json_v9_40$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('chah_1_listen_01', 'chah', 1, 'listen', 1, 'Rain Water', 300, $json_v9_41$[{"t":"00:00","name":"Rain water","note":"Before it fell into the canal, it was clear."},{"t":"01:00","name":"Reading the label","note":"People debate the medicine. They do not take it."},{"t":"02:30","name":"The walking instruction","note":"Feet touch ground. Mind wanders. Return. That's the whole thing."},{"t":"04:00","name":"Not for sure","note":"\"How was your practice?\" He'd smile. Enough for today."}]$json_v9_41$::jsonb, $json_v9_42${"episode":"01","narrator":"Ajahn Chah · CHA-030, CHA-001, CHA-004, CHA-097","duration":"05:00","duration_sec":300,"chapters":[{"t":"00:00","name":"Rain water","note":"Before it fell into the canal, it was clear."},{"t":"01:00","name":"Reading the label","note":"People debate the medicine. They do not take it."},{"t":"02:30","name":"The walking instruction","note":"Feet touch ground. Mind wanders. Return. That's the whole thing."},{"t":"04:00","name":"Not for sure","note":"\"How was your practice?\" He'd smile. Enough for today."}]}$json_v9_42$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('chah_1_understand_01', 'chah', 1, 'understand', 1, 'The mind is already pure. Practice is removing the dye from rain water — not manufacturing clarity.', $json_v9_43${"model_title":"The mind is already pure. Practice is removing the dye from rain water — not manufacturing clarity.","core_label":"น้ำฝน · rain water","layers":[{"label":"Surface colors · passing"},{"label":"Thoughts · plans · reactions"},{"label":"Original clarity · always here"},{"label":"Rain water · the mind itself"}],"concepts":[{"term":"น้ำฝน","romanized":"RAIN WATER · THE ORIGINAL MIND","note":"Before it falls into the canal, before it mixes with sediment or dye — rain water is just rain water. \"The mind is originally pure.\" You are not building purity. You are remembering it."},{"term":"ฉลากยา","romanized":"THE MEDICINE LABEL","note":"Chah pointed at bottles and asked: \"Have you read the label?\" People read for years. They debate ingredients. They do not take the medicine. Reading about meditation is the label. Sitting and breathing — that is the medicine."},{"term":"ทั้ง ๔ อิริยาบถ","romanized":"ALL FOUR POSTURES","note":"Walking, standing, sitting, lying down. The whole day is the field — not just the cushion. Thai Forest practice is not a scheduled event inside a life. It is the shape of the life itself."}],"comparison":[{"label":"Reading about the path","v":0.72},{"label":"Walking — feet on ground","v":0.35},{"label":"Return, without judgment","v":0.52}]}$json_v9_43$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('chah_1_reflect_01', 'chah', 1, 'reflect', 1, 'The Outer Path · reflection prompts', $json_v9_44${"questions":[{"prompt":"When you began walking today, was there a moment before you started thinking about anything? Can you remember what that felt like?","sub":"No right answer. Just: was there a moment?","choices":[{"label":"I can't recall one — thinking was already there","v":1},{"label":"Maybe a second or two before thoughts started","v":2},{"label":"Yes, a clear small window of just walking","v":3},{"label":"A longer stretch of simply being present","v":4}]},{"prompt":"Chah said most of us are wanderers who forgot the address of home. What does \"feeling at home\" in your own mind feel like to you?","sub":"Even briefly.","choices":[{"label":"I'm not sure I've felt it","v":1},{"label":"A rare glimpse, hard to describe","v":2},{"label":"Something familiar — quieter than thought","v":3},{"label":"A place I can find and stay with","v":4}]},{"prompt":"During the walk today, did you notice your feet touching the ground?","sub":"Once, twice, or did you forget entirely? All three are fine.","choices":[{"label":"I forgot entirely — that's fine","v":1},{"label":"Once or twice near the end","v":2},{"label":"Several times, with gentle return","v":3},{"label":"The contact was a quiet thread through the walk","v":4}]},{"prompt":"What is one thing you were carrying in your mind today that you didn't choose to pick up?","choices":[{"label":"I couldn't name what I was carrying","v":1},{"label":"Something, but I noticed late","v":2},{"label":"I saw it clearly and could set it down briefly","v":3},{"label":"I noticed, softened, and kept walking","v":4}]},{"prompt":"Chah said you don't have to make the mind pure — it already is. Does that feel like good news, a strange idea, or both?","choices":[{"label":"It sounds like a platitude","v":1},{"label":"Strange — I'm not sure what to do with it","v":2},{"label":"Both — strange and a relief","v":3},{"label":"Good news I am beginning to taste","v":4}]}],"bands":[{"label":"ARRIVING","title":"You are beginning.","note":"Chah would not give you a grim assessment. He would smile. The medicine bottle has a label — and you've now started to open it. The rest is walking.","suggestion":"Listen: \"Rain Water\" · a 15-minute walk noticing only the feet."},{"label":"REMEMBERING","title":"The home is close.","note":"The mind wanders, and the noticing returns. This is the practice — not the stillness, the returning. Chah: \"Just keep walking.\"","suggestion":"Understand: \"The Rain Water Diagram\" · then walk with Sammā Arahaṃ of your own breath."},{"label":"NOT FOR SURE","title":"You have found the first ground.","note":"You can meet the walk without grasping. The mind quiets on its own. Do not claim this. The water is still settling.","suggestion":"Reflect: \"Five Questions to Carry on the Walk\" · then enter The Quiet Ground."}]}$json_v9_44$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('chah_2_listen_01', 'chah', 2, 'listen', 1, 'The Glass Is Already Broken', 300, $json_v9_45$[{"t":"00:00","name":"The favorite glass","note":"\"I love this glass. And it is already broken.\""},{"t":"00:45","name":"ไม่แน่ — not for sure","note":"A precision instrument, not a pessimism"},{"t":"02:15","name":"The pen in the pocket","note":"Searching frantically. It was there the whole time."},{"t":"03:15","name":"⚠️ The rock on the grass","note":"Samādhi suppresses. Only wisdom uproots."},{"t":"04:30","name":"If the body is disturbed","note":"\"Make sure the mind isn't disturbed.\""}]$json_v9_45$::jsonb, $json_v9_46${"episode":"02","narrator":"Ajahn Chah · CHA-014, CHA-015, CHA-024, CHA-035","duration":"05:00","duration_sec":300,"chapters":[{"t":"00:00","name":"The favorite glass","note":"\"I love this glass. And it is already broken.\""},{"t":"00:45","name":"ไม่แน่ — not for sure","note":"A precision instrument, not a pessimism"},{"t":"02:15","name":"The pen in the pocket","note":"Searching frantically. It was there the whole time."},{"t":"03:15","name":"⚠️ The rock on the grass","note":"Samādhi suppresses. Only wisdom uproots."},{"t":"04:30","name":"If the body is disturbed","note":"\"Make sure the mind isn't disturbed.\""}]}$json_v9_46$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('chah_2_understand_01', 'chah', 2, 'understand', 1, 'Not a timeline of impermanence — a compass rose. Everything in the circle is "not for sure."', $json_v9_47${"model_title":"Not a timeline of impermanence — a compass rose. Everything in the circle is \"not for sure.\"","core_label":"ไม่แน่","layers":[{"label":"A pleasant thought · not for sure"},{"label":"A conclusion about yourself · not for sure"},{"label":"A state of calm · not for sure"},{"label":"This moment · arising, leaving"}],"concepts":[{"term":"ไม่แน่","romanized":"MAI NAE · NOT FOR SURE","note":"Not pessimism. A precision instrument. When a good feeling arises — not for sure. When a bad feeling arises — not for sure. When a state of calm arises — not for sure. \"Whoever sees that things are not for sure, sees for sure that that's the way they are.\""},{"term":"แก้วแตกแล้ว","romanized":"THE GLASS IS ALREADY BROKEN","note":"Chah held up his favorite glass. \"I love this glass. It holds water well. It has a nice weight.\" Then: \"This glass is already broken.\" Not broken — already broken. He had seen it shattered already. So while whole, he used it well, enjoyed it, and was not waiting for the day it broke to begin grieving."},{"term":"หินทับหญ้า","romanized":"⚠️ ROCK ON GRASS · THE CANDY WARNING","note":"Samādhi — the calm from practice — is like a rock placed on grass. The grass is flattened. It looks gone. Lift the rock: the grass returns immediately. Calm suppresses defilements. It does not remove them. Calm is necessary. It is not the destination. The destination is clarity."}],"comparison":[{"label":"Grasping the pleasant","v":0.68},{"label":"Pushing away the difficult","v":0.58},{"label":"Holding lightly — not for sure","v":0.32}]}$json_v9_47$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('chah_2_reflect_01', 'chah', 2, 'reflect', 1, 'The Quiet Ground · reflection prompts', $json_v9_48${"questions":[{"prompt":"During this walk, did anything feel solid and certain? Has anything shifted since you started?","choices":[{"label":"Everything felt fixed — I didn't notice shifts","v":1},{"label":"One or two things loosened a little","v":2},{"label":"Several solid things turned out to be moving","v":3},{"label":"The sense of \"solid\" itself loosened","v":4}]},{"prompt":"The glass is already broken. Does that feel terrifying, freeing, or both today?","choices":[{"label":"Mostly terrifying","v":1},{"label":"Uncomfortable — I resist it","v":2},{"label":"Both — and I can stay with both","v":3},{"label":"Freeing — it softens how I hold what I love","v":4}]},{"prompt":"⚠️ Candy Check: Did you experience a feeling of calm during the walk? Where do you think it came from — did you \"make\" it happen, or did it arrive on its own?","sub":"Chah: the calm from practice is like a rock on grass. Real, helpful, not permanent.","choices":[{"label":"I forced it — it felt like work","v":1},{"label":"I forced it, then softened, and something came","v":2},{"label":"It arrived when I stopped reaching","v":3},{"label":"It was there — I just noticed it","v":4}]},{"prompt":"\"If the body is disturbed, don't worry about it. Make sure the mind isn't disturbed.\" Was your body disturbed today? What happened in the mind?","choices":[{"label":"Body disturbed, mind followed it into disturbance","v":1},{"label":"Some struggle, some recovery","v":2},{"label":"The mind stayed mostly steady","v":3},{"label":"The mind watched the ache without becoming it","v":4}]},{"prompt":"What is one thing that felt \"not for sure\" during today's walk that you hadn't noticed before?","choices":[{"label":"I couldn't catch anything","v":1},{"label":"Something small — a mood, a thought","v":2},{"label":"Something I had been taking as solid","v":3},{"label":"The sense of a fixed self loosened briefly","v":4}]}],"bands":[{"label":"STILL GRIPPING","title":"The glass still feels permanent.","note":"This is where everyone starts. \"Not for sure\" has to be walked, not understood. Every solid thing you notice and release is the practice working.","suggestion":"Listen: \"The Glass Is Already Broken\" · a 20-minute walk, with \"not for sure\" on each exhale."},{"label":"LOOSENING","title":"The grip is softening.","note":"You can see a few things as arising-and-passing. Do not force this onto everything. The ones that loosen on their own are the real ones.","suggestion":"Understand: \"ไม่แน่ — The Impermanence Map\" · sit after a walk and watch what changes."},{"label":"NOT FOR SURE","title":"The phrase has become a practice.","note":"You carry \"not for sure\" without being morbid. Pleasant states are held lightly. The glass is whole, and already broken, and that is fine.","suggestion":"Reflect: \"Five Questions — Not for Sure\" · then enter The Inner Forest."}]}$json_v9_48$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('chah_3_listen_01', 'chah', 3, 'listen', 1, 'Still, Flowing Water', 330, $json_v9_49$[{"t":"00:00","name":"Still, flowing water","note":"\"You've never seen still, flowing water.\" Then he laughed."},{"t":"00:45","name":"The farmer and the buffalo","note":"Behind and to the side. Not chasing."},{"t":"02:15","name":"ผู้รู้ — the one who knows","note":"Not the thinker. Not the judge. The knowing itself."},{"t":"03:45","name":"⚠️ Drunk on Dhamma","note":"The peace is pleasant. Don't mistake the bar for home."},{"t":"04:45","name":"The center of the web","note":"The spider sits still. Feels every vibration."}]$json_v9_49$::jsonb, $json_v9_50${"episode":"03","narrator":"Ajahn Chah · CHA-010, CHA-018, CHA-047, CHA-048","duration":"05:30","duration_sec":330,"chapters":[{"t":"00:00","name":"Still, flowing water","note":"\"You've never seen still, flowing water.\" Then he laughed."},{"t":"00:45","name":"The farmer and the buffalo","note":"Behind and to the side. Not chasing."},{"t":"02:15","name":"ผู้รู้ — the one who knows","note":"Not the thinker. Not the judge. The knowing itself."},{"t":"03:45","name":"⚠️ Drunk on Dhamma","note":"The peace is pleasant. Don't mistake the bar for home."},{"t":"04:45","name":"The center of the web","note":"The spider sits still. Feels every vibration."}]}$json_v9_50$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('chah_3_understand_01', 'chah', 3, 'understand', 1, 'The farmer does not chase the buffalo. The knower does not chase the mind. Watch from the bund.', $json_v9_51${"model_title":"The farmer does not chase the buffalo. The knower does not chase the mind. Watch from the bund.","core_label":"ผู้รู้ · the knower","layers":[{"label":"The field · defilements / kilesa"},{"label":"The buffalo · the mind itself"},{"label":"The rope · light contact, not force"},{"label":"ผู้รู้ · the one who watches"}],"concepts":[{"term":"ผู้รู้","romanized":"PŪ-RŪ · THE ONE WHO KNOWS","note":"Not the thinker. Not the judge. Not a homunculus inside the head. The quality of awareness itself — steady, watchful, unafraid. What notices the sounds as you walk? What notices when the mind wanders, and what notices the return? That. For now, that is ผู้รู้."},{"term":"ชาวนาและควาย","romanized":"THE FARMER AND THE BUFFALO","note":"The buffalo is large, strong, wants to eat the rice plants. The farmer doesn't run behind yanking the rope. The farmer walks behind and to the side — watching, letting the buffalo work, rope just taut enough to guide. The buffalo is the mind. The farmer is ผู้รู้."},{"term":"น้ำไหลนิ่ง","romanized":"STILL, FLOWING WATER","note":"Chah asked monks: \"Have you ever seen still, flowing water?\" They were silent. Still water is still. Flowing water flows. Then he laughed. At depth, samādhi and vipassanā are not two things. The still water and the flowing water, together — the pause is the teaching."}],"comparison":[{"label":"Fighting the mind","v":0.42},{"label":"Chasing pleasant states","v":0.38},{"label":"Watching from the bund","v":0.68}]}$json_v9_51$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('chah_3_reflect_01', 'chah', 3, 'reflect', 1, 'The Inner Forest · reflection prompts', $json_v9_52${"questions":[{"prompt":"Was there a moment today where you noticed you were distracted — and then noticed that you had noticed?","sub":"The second noticing. What was it like?","choices":[{"label":"I didn't catch the second noticing","v":1},{"label":"Once or twice, briefly","v":2},{"label":"Several times, with a kind of lift","v":3},{"label":"The second noticing was steady, almost continuous","v":4}]},{"prompt":"Chah described ผู้รู้ as purity, radiance, and peace. Did you find any trace of those three today? Even a glimpse of one?","choices":[{"label":"No — they sound abstract","v":1},{"label":"A flicker of one, briefly","v":2},{"label":"One or two, clearly","v":3},{"label":"All three, at different moments","v":4}]},{"prompt":"The visitor chair: if you are sitting in it, a visitor cannot. Did a distracting thought today simply have nowhere to land?","choices":[{"label":"Every thought landed and stayed","v":1},{"label":"A few found no seat, briefly","v":2},{"label":"The chair was often occupied by presence","v":3},{"label":"Thoughts passed through without requiring response","v":4}]},{"prompt":"⚠️ Candy Check: Did today's practice produce a pleasant feeling? Was it in the stillness — or in the watching?","sub":"This distinction matters. The peace of samādhi is not the same as the peace of ผู้รู้.","choices":[{"label":"Pleasant, and I grabbed it","v":1},{"label":"Pleasant, and I noticed the grabbing","v":2},{"label":"Pleasant, and I could locate where it lived","v":3},{"label":"Pleasant — and I saw who was pleased","v":4}]},{"prompt":"What is the \"monkey\" in your mind right now — the recurring thing that wants attention? What would it feel like to understand it without following it?","choices":[{"label":"I follow it — I don't see it as a monkey yet","v":1},{"label":"I see it; I still usually follow","v":2},{"label":"I can sometimes watch without following","v":3},{"label":"The monkey passes through. I am not the monkey.","v":4}]}],"bands":[{"label":"FINDING THE WATCHER","title":"ผู้รู้ is a word, not yet a place.","note":"This is the right starting point. Keep walking. The farmer does not appear on command — but each time you notice you had been swept along, you have found a seat on the bund.","suggestion":"Listen: \"Still, Flowing Water\" · a 20-minute walk noticing the noticing."},{"label":"THE BUND","title":"You are watching the buffalo.","note":"You can feel the difference between being the mind and watching the mind. Don't hold this too tightly. It is real, and it is not the end.","suggestion":"Understand: \"The Farmer, the Buffalo, the Field\" · sit with the knower present."},{"label":"KNOWING","title":"ผู้รู้ is steady.","note":"The knower is familiar. Purity, radiance, peace have each been glimpsed. ⚠️ At the next stage, this very watcher will be questioned. Not to dismantle. To deepen.","suggestion":"Reflect: \"Five Questions — The Watcher\" · then enter The Silent Temple."}]}$json_v9_52$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('chah_4_listen_01', 'chah', 4, 'listen', 1, 'The Turtle with a Moustache', 330, $json_v9_53$[{"t":"00:00","name":"Turtle with a moustache","note":"Delivered straight. The joke lands later."},{"t":"00:45","name":"The snake's head and tail","note":"Both bite. Don't grab either end."},{"t":"01:45","name":"⚠️ The red-hot iron ball","note":"Every part is hot. There is no cool spot in the ball."},{"t":"03:15","name":"ผู้รู้ as subtle trap","note":"\"If your peace can be disturbed, it is not real peace yet.\""},{"t":"04:45","name":"Wax, chicken dung, name","note":"All conventions. Real in their realm. Not ultimate."}]$json_v9_53$::jsonb, $json_v9_54${"episode":"04","narrator":"Ajahn Chah · CHA-099, CHA-042, CHA-046, CHA-050","duration":"05:30","duration_sec":330,"chapters":[{"t":"00:00","name":"Turtle with a moustache","note":"Delivered straight. The joke lands later."},{"t":"00:45","name":"The snake's head and tail","note":"Both bite. Don't grab either end."},{"t":"01:45","name":"⚠️ The red-hot iron ball","note":"Every part is hot. There is no cool spot in the ball."},{"t":"03:15","name":"ผู้รู้ as subtle trap","note":"\"If your peace can be disturbed, it is not real peace yet.\""},{"t":"04:45","name":"Wax, chicken dung, name","note":"All conventions. Real in their realm. Not ultimate."}]}$json_v9_54$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('chah_4_understand_01', 'chah', 4, 'understand', 1, 'The path is not between pleasure and pain. It is orthogonal — a different direction entirely.', $json_v9_55${"model_title":"The path is not between pleasure and pain. It is orthogonal — a different direction entirely.","core_label":"เต่ามีหนวด","layers":[{"label":"Head · pleasant states, jhāna (bites)"},{"label":"Tail · difficulty, doubt (bites)"},{"label":"Middle · trying to balance · still caught"},{"label":"Orthogonal · understanding the snake"}],"concepts":[{"term":"เต่ามีหนวด","romanized":"THE TURTLE WITH A MOUSTACHE","note":"\"Looking for peace is like looking for a turtle with a moustache.\" Delivered completely straight. \"You won't find it. But when your heart is ready, peace will come and look for you.\" The joke lands, eventually, as the teaching."},{"term":"หัวและหางงู","romanized":"THE SNAKE'S HEAD AND TAIL","note":"Both bite. If you grab happiness — \"I've found it, let me keep it\" — you're bitten when it changes. If you grab unhappiness — \"this is wrong, fix it\" — bitten by that. The path is not in the middle of the snake. It is orthogonal to the whole snake."},{"term":"ผู้รู้เป็นกับดัก","romanized":"⚠️ THE KNOWER AS TRAP","note":"ผู้รู้ is real — do not abandon it. But the farmer can start identifying with the watching: \"I am the watcher.\" A subtle, refined self — still grasping. Chah's test: \"If your peace can be disturbed, it is not real peace yet.\" A slammed door disturbs the farmer who was attached to quiet fields."}],"comparison":[{"label":"Chasing the pleasant end","v":0.48},{"label":"Being the watcher (superior seat)","v":0.55},{"label":"Who is looking for the watcher?","v":0.35}]}$json_v9_55$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('chah_4_reflect_01', 'chah', 4, 'reflect', 1, 'The Silent Temple · reflection prompts', $json_v9_56${"questions":[{"prompt":"During this walk, was there any moment where you caught yourself \"being the watcher\" — holding a slightly superior position above your thoughts?","sub":"Not a failure. A data point.","choices":[{"label":"I don't know what that feels like","v":1},{"label":"I sense it but couldn't catch it in the act","v":2},{"label":"I caught it, and saw the subtle grasp","v":3},{"label":"The \"superior seat\" has become thin","v":4}]},{"prompt":"Chah said: \"If your peace can be disturbed, it is not real peace yet.\" Was your peace disturbed by anything today?","choices":[{"label":"Disturbed constantly","v":1},{"label":"Disturbed, and I reacted","v":2},{"label":"Disturbed, and I watched the disturbance","v":3},{"label":"Peace that does not depend on conditions being quiet","v":4}]},{"prompt":"The turtle with a moustache: \"When your heart is ready, peace will come and look for you.\" What does \"being ready\" feel like to you? Is it something you can make happen?","choices":[{"label":"I keep trying to make it happen","v":1},{"label":"I notice the trying, but still try","v":2},{"label":"The trying has softened into waiting","v":3},{"label":"Neither making nor waiting — just walking","v":4}]},{"prompt":"Money = wax = chicken dung. Your name is a supposition. Does that feel liberating, threatening, or abstract? What in you wants to hold onto the name?","choices":[{"label":"Threatening — I need the name","v":1},{"label":"Abstract — it doesn't reach me","v":2},{"label":"Both threatening and freeing","v":3},{"label":"Freeing — the name is light, not heavy","v":4}]},{"prompt":"⚠️ Candy Check — the hardest one: In your practice so far, has there been a state or experience that felt like \"it\" — the thing you were looking for? Where is that experience now?","sub":"Honest. Chah would ask you directly.","choices":[{"label":"Yes, and I'm still trying to get it back","v":1},{"label":"Yes, and I've noticed I was holding onto it","v":2},{"label":"Yes, and I can now let it go when it arises","v":3},{"label":"The \"it\" was already passing when I named it","v":4}]}],"bands":[{"label":"GRABBING THE SNAKE","title":"The bite is still the teacher.","note":"This is rigorous work. Being bitten — by pleasant states lost, by difficult ones resisted — is the practice at this stage. Chah is not gentle here. Neither is what is true.","suggestion":"Listen: \"The Turtle with a Moustache\" · a long walk, asking: who is looking?"},{"label":"SEEING THE TRAP","title":"ผู้รู้ has been questioned.","note":"You have noticed the subtle seat of the watcher. This is the beginning of its thinning. Do not demolish it — just keep asking.","suggestion":"Understand: \"The Snake's Head and Tail\" · sit without taking a position."},{"label":"ORTHOGONAL","title":"The path is no longer between the ends.","note":"You can walk with neither grasping nor pushing. The watcher is quieter. The question \"who is watching?\" no longer needs an answer. Peace may arrive — or not. It is not the issue.","suggestion":"Reflect: \"Five Questions — Who Is Watching?\" · then enter Open Awareness."}]}$json_v9_56$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, duration_sec, chapters, body, published)
  values
  ('chah_5_listen_01', 'chah', 5, 'listen', 1, 'The Tree in a Forest', 300, $json_v9_57$[{"t":"00:00","name":"Are you an arahant?","note":"\"I am like a tree in a forest.\""},{"t":"01:00","name":"The lotus leaf","note":"In water, not soaked."},{"t":"02:00","name":"Oil and water","note":"Present, not mixing."},{"t":"02:45","name":"Virtue, stillness, wisdom — one","note":"The mango at full ripeness."},{"t":"04:00","name":"Wild chickens","note":"Walk through the village. Do not forget the forest."}]$json_v9_57$::jsonb, $json_v9_58${"episode":"05","narrator":"Ajahn Chah · CHA-060, CHA-086, CHA-090, CHA-051","duration":"05:00","duration_sec":300,"chapters":[{"t":"00:00","name":"Are you an arahant?","note":"\"I am like a tree in a forest.\""},{"t":"01:00","name":"The lotus leaf","note":"In water, not soaked."},{"t":"02:00","name":"Oil and water","note":"Present, not mixing."},{"t":"02:45","name":"Virtue, stillness, wisdom — one","note":"The mango at full ripeness."},{"t":"04:00","name":"Wild chickens","note":"Walk through the village. Do not forget the forest."}]}$json_v9_58$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('chah_5_understand_01', 'chah', 5, 'understand', 1, 'No more arrows. No more taxonomy. Just the tree — full, luminous, not knowing itself.', $json_v9_59${"model_title":"No more arrows. No more taxonomy. Just the tree — full, luminous, not knowing itself.","core_label":"ต้นไม้ในป่า","layers":[{"label":"Birds come to eat and nest"},{"label":"Animals rest in its shade"},{"label":"Blossoms and fruit arrive in season"},{"label":"The tree does not know itself"}],"concepts":[{"term":"ต้นไม้ในป่า","romanized":"THE TREE IN A FOREST","note":"A student asked: \"Luang Por, are you an arahant?\" He was quiet a long time. Then: \"I am like a tree in a forest. Full of leaves, blossoms, and fruit. Birds come to eat and nest. Animals seek rest in its shade. Yet the tree does not know itself. It follows its own nature. It is as it is.\""},{"term":"ใบบัว","romanized":"THE LOTUS LEAF","note":"The lotus grows in water, surrounded by water, depends on water. But the lotus leaf is not soaked. A drop lands, rolls off. Present in the water without being penetrated by it. Not someone who left the world — someone who entered it completely and remained dry."},{"term":"น้ำมันกับน้ำ","romanized":"OIL AND WATER","note":"The Buddha lived with senses fully functional. He heard, tasted, encountered people. Like oil dropped in water — present, not mixing. Not detachment in the cold sense. Presence so complete that it needs nothing from the experience to confirm itself."}],"comparison":[{"label":"Practice as something to do","v":0.2},{"label":"Practice as the shape of the day","v":0.55},{"label":"No practice — only the walking","v":0.82}]}$json_v9_59$::jsonb, true)
insert into public.teaching_units
  (id, lineage_id, stage_index, mode, order_index, title, body, published)
  values
  ('chah_5_reflect_01', 'chah', 5, 'reflect', 1, 'Open Awareness · reflection prompts', $json_v9_60${"questions":[{"prompt":"At the beginning of Stage 1, were you looking for something from this practice? What were you hoping to find?","sub":"No answer required. The memory itself is the question.","choices":[{"label":"I'm still looking for what I came for","v":1},{"label":"The hope has shifted but not released","v":2},{"label":"The hope has thinned","v":3},{"label":"I can't quite remember what I was looking for","v":4}]},{"prompt":"Where are you now, relative to that hope? Not better or worse — just: where?","choices":[{"label":"Further from it","v":1},{"label":"In a different place, equally far","v":2},{"label":"Somewhere the hope no longer applies","v":3},{"label":"Here — and \"where\" has stopped being the question","v":4}]},{"prompt":"Chah said: letting go a little brings peace a little; letting go completely brings peace completely. What is the last thing you are still holding onto?","sub":"No answer required. This is the question to carry, not the question to answer today.","choices":[{"label":"Many things — I haven't named them","v":1},{"label":"A few, clearly","v":2},{"label":"One — and I see my hand on it","v":3},{"label":"The hand itself is beginning to soften","v":4}]},{"prompt":"The tree doesn't know itself. It just follows its nature. Has any of these sessions felt like following your nature rather than doing a technique?","choices":[{"label":"It all still feels like technique","v":1},{"label":"Technique, with moments of letting go","v":2},{"label":"Often more like following than doing","v":3},{"label":"The distinction has thinned","v":4}]},{"prompt":"Rain water. You started here. After all of this: is it different, or is it the same, and you are different?","sub":"This is the question. Take as long as you need.","choices":[{"label":"Different, I think","v":1},{"label":"I'm not sure which","v":2},{"label":"Same — and I am quieter around it","v":3},{"label":"The same rain water. The one standing in it has thinned.","v":4}]}],"bands":[{"label":"ARRIVING","title":"The tree is close.","note":"You have walked five stages. Something has changed, not with trumpets. Keep walking. The tree does not announce itself.","suggestion":"Listen: \"The Tree in a Forest\" · a walk with no agenda. Return when it ends."},{"label":"LOTUS LEAF","title":"Present, not soaked.","note":"You can enter the water of the day without being penetrated by it. The practice has become how you live, not what you do.","suggestion":"Understand: \"The Tree Does Not Know Itself\" · sit without naming what is happening."},{"label":"AS IT IS","title":"It is as it is.","note":"You have completed the curriculum. The tree does not know itself. You cannot check whether you have arrived. That is what the path looks like at the end.\n\nThank you for walking.","suggestion":"Keep walking."}]}$json_v9_60$::jsonb, true)
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('mun', 1, 'Know in the body, see in the body — when you know within, you know everywhere, because the self is the root cause of all experience.', 'Luang Pu Mun · บันทึกข้อธรรม')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('mun', 2, 'When paññā is mature, sīla and samādhi are present simultaneously — like cooked rice that needs no further preparation.', 'Luang Pu Mun · บันทึกข้อธรรม')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('mun', 3, 'Do not make the mind lean outward. Know within. See within.', 'Luang Pu Mun · บันทึกข้อธรรม')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('mun', 4, 'Nibbana: the mind contracts to find its original self. Great mindfulness surrounding mindfulness, great wisdom surrounding wisdom — then seeing normalcy.', 'Luang Pu Mun · บันทึกข้อธรรม')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('mun', 5, 'Paccattaṃ veditabbo viññūhi — truth is known inwardly, by the wise, for themselves. It cannot be borrowed, transmitted, or scheduled.', 'Luang Pu Mun · ปฏิปัตติปุจฉาวิสัชนา')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('sodh', 1, 'Hold on to Sammā Arahaṃ. All other techniques you will eventually forget. This one remains.', 'Luang Pu Sodh · to early students')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('sodh', 2, 'Stopping is what makes it fast. The whole path — from first sphere to the arahant body — is traversed by stopping, not by going.', 'Luang Pu Sodh · สาระสำคัญ')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('sodh', 3, 'The sphere is not created by meditation. It is revealed by stillness. The silt settles, and the bottom of the stream appears.', 'Luang Pu Sodh · วิสุทธิวาจา 1')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('sodh', 4, 'From the human body to the refined formless brahma body — that is samatha. To go further, you must cross a boundary.', 'Luang Pu Sodh · สาระสำคัญ p.15')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('sodh', 5, 'Stopping — only stopping. The entire path from first sphere to arahant body is traversed this way. If you do not stop, you do not go. This is clear.', 'Luang Pu Sodh · สาระสำคัญ')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('chah', 1, 'The mind is originally pure. It is like rain water which is naturally clean.', 'Ajahn Chah')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('chah', 2, 'Whoever sees that things aren''t for sure, sees for sure that that''s the way they are.', 'Ajahn Chah')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('chah', 3, 'The one who knows — ผู้รู้ — does not chase the rice plants. It just watches.', 'Ajahn Chah')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('chah', 4, 'Looking for peace is like looking for a turtle with a moustache. You won''t find it. When your heart is ready, it will come and look for you.', 'Ajahn Chah')
insert into public.teacher_quotes
  (lineage_id, stage_index, english_text, source_ref)
  values
  ('chah', 5, 'I am like a tree in a forest. The tree does not know itself. It follows its own nature. It is as it is.', 'Ajahn Chah')
